/* AS-IS 함수 관련 */

scwin.onpageload = function() {

};

scwin.cfDownloadFile = async function (fileName, filePath) {
    if ($c.util.isEmpty(filePath)) {
        $c.win.alert("대상 파일이 NULL입니다. 설정값을 확인하세요.");
        return;
    }

    try {
        const response = await fetch(scwin.buildDownloadRequestURL(fileName, filePath, "DOWN"));

        if (response.status === 404) {
            $c.win.alert("해당 파일[" + filePath + "]이 존재하지 않습니다.");
            return;
        }

        if (response.status === 500) {
            $c.win.alert("서버 오류입니다.");
            return;
        }

        if (!response.ok) {
            $c.win.alert("파일 다운로드 중 오류가 발생했습니다.");
            return;
        }

        const result = await response.json();
        if (!result.downloadUrl) {
            $c.win.alert("다운로드 URL 생성에 실패했습니다.");
            return;
        }

        window.location.href = result.downloadUrl;
    } catch (e) {
        console.error(e);
        $c.win.alert("다운로드 처리 중 예외가 발생했습니다.");
    }
};

/**
 * @method
 * @name cfGetAuthCode
 * @description 권한 코드  정보를 반환한다.
 * @param {string} param1 desc
 * @returns
 * @hidden N
 * @exception
 * @example
 * $c.gus.cfGetAuthCode(authStr)
 */
scwin.cfGetAuthCode = function( authStr ) {
    if ( authStr == "C" ) return 40 ;
    else if ( authStr == "D" ) return 30 ;
    else if ( authStr == "U" ) return 20 ;
    else if ( authStr == "R" ) return 10 ;
    else return 100 ;
  }

/**
 * @method
 * @name cfCheckAuth
 * @description 해당 권한을 가지고 있는지 여부를  반환한다. userAuth에 ":"으로 분리되어 설정된 모든 권한이 있을 경우에만 true를 리턴한다.
 * @param {string} baseAuth desc
 * @returns
 * @hidden N
 * @exception
 * @example $c.gus.cfCheckAuth(baseAuth)
 */
scwin.cfCheckAuth = function (baseAuth) {
    let isAuth = true;
  	let auths = baseAuth.split(":");
  	let checkFlag = 0 ;

    let frame = scwin.getFrm();
    // let frame = $p.getFrame();

    if(location.host.indexOf("ebiz.") == -1 && $p.top().$p.isPopup() && !$p.top().$p.isWFramePopup()) {
        frame = WebSquare.getBody();
    }

	for (var i = 0; i < auths.length; i++) {
	  	switch (auths[i]) {
	  	// 프린트
	  	case 'P':
	  		isAuth = scwin.cfCheckAuthPRINT(frame);
	  		break;
	  	// 엑셀 다운로드
	  	case 'X':
	  		isAuth = scwin.cfCheckAuthEXCEL(frame);
	  		break;
	  	// CRUD
	  	case 'C':
	     	isAuth = scwin.cfCheckAuthCREATE(frame);
	  		break;
	  	case 'R':
	        isAuth = scwin.cfCheckAuthRETRIEVE(frame);
	  		break;
	  	case 'U':
	        isAuth = scwin.cfCheckAuthUPDATE(frame);
	  		break;
	  	case 'D':
	  		isAuth = scwin.cfCheckAuthDELETE(frame);
	  		break;
	  	default:
	  		alert("'" + auths[i] + "'는 정의되지 않은 권한코드입니다");
	  		isAuth = false;
	  		break;
		}

		if(isAuth==true) {
			checkFlag = checkFlag+1;
        }
		if (auths.length==1 && isAuth == false) {
			return false;
        }
	} // end for

	if(auths.length>1 && checkFlag>0) {
		return true;
	} else if(auths.length>1 && checkFlag==0) {
		return false;
    }

  	return true;
  }

