/**
 * @method
 * @name cfCanOpenPopup
 * @description 팝업을 띄울 수 있는지 오브젝트를 검사한다.
 * @param {string} inObj desc
 * @param {string} pairObj desc
 * @returns
 * @hidden N
 * @exception
 * @example $c.gus.cfCanOpenPopup(inObj, pairObj)
 */
scwin.cfCanOpenPopup = function (inObj, pairObj) {

    try {
        let obj = $c.gus.object(inObj);
        if(scwin.cfGetValue(obj) == "") {
            scwin.cfClearPairObj(inObj);
            scwin.cfClearPairObj(pairObj);

		    if (inObj.options.hidVal != null) inObj.options.hidVal = "";
		    if (pairObj.options.hidVal != null) pairObj.options.hidVal = "";

            return false;
        }

        if(scwin.cfGetElementType(inObj) == "input") {
            if (inObj.getReadOnly() || inObj.getDisabled() || scwin.cfGetValue(inObj)+scwin.cfGetValue(pairObj) == scwin.cfGetHiddenValue(inObj)+scwin.cfGetHiddenValue(pairObj)) {
                return false;
            } else {
                return true;
            }
        } else {
            return false;
        }

    } catch(e) {
        console.log("cfCanOpenPopup::"+e);
    }  

};



