/**
 * @method
 * @name cfLimitByteLength
 * @description input type=text와 textarea에 입력 문자 길이를 제한
 * @param {string} inputObj desc
 * @param {string} maxLength desc
 * @returns
 * @hidden N
 * @exception
 * @example   $c.gus.cfLimitByteLength(inputObj, maxLength)
 */
scwin.cfLimitByteLength = async function (inputObj, maxLength) {
    var obj = $c.gus.object(inputObj);
    var inputVal = obj.getValue();

	if (scwin.cfGetByteLength(inputVal) > maxLength) {
		await $c.win.alert(maxLength + " byte까지만 입력이 가능합니다.\n(영문/숫자:1byte, 한글:2byte)");

		while (scwin.cfGetByteLength(inputVal) > maxLength) {
			inputVal = inputVal.substring(0, inputVal.length-1);
		}
		obj.setValue(inputVal);
	}
};

/**
 * @method
 * @name cfIsAfterDate
 * @description  YYYYMMDD 형식의 두 개의 날짜를 받아서 체크
 * @param {string} startDate desc
 * @param {string} endDate desc
 * @param {string} exceptSameDate desc
 * @returns
 * @hidden N
 * @exception
 * @example   $c.gus.cfIsAfterDate(startDate, endDate, exceptSameDate)
 */
scwin.cfIsAfterDate = function (startDate, endDate, exceptSameDate) {
    var sDate = startDate.toDate();
	var eDate = endDate.toDate();

	if (exceptSameDate != null && exceptSameDate == true) {
		if (sDate < eDate) {
			return true;
        } else {
			return false;
        }
	} else {
		if (sDate <= eDate) {
			return true;
        } else {
			return false;
        }
	}
};

/**
 * @method
 * @name cfEnableAllBtn
 * @description 모든 버튼을 enable(클릭가능) 상태로 변경한다.
 * @param
 * @returns
 * @hidden N
 * @exception
 * @example   $c.gus.cfEnableAllBtn()
 */
scwin.cfEnableAllBtn = function () {//debugger;
    // ctrlBtn 배열의 모든 버튼을 enable시킨다
    // let frame = $p.getFrame();
    let frame = scwin.getFrm();
	for (var i in frame.ctrlBtn) {
        if (frame.ctrlBtn[i] != null) {
            // scwin.cfEnableObj($c.global.ctrlBtn[i].id, true);
            scwin.cfEnableObj(frame.ctrlBtn[i], true);
        }
    }

	// 신규
	if (frame.bCreate != null) {
    	scwin.cfEnableObj(frame.bCreate, true);
    }
	// 수정
	if (frame.bUpdate != null) {
    	scwin.cfEnableObj(frame.bUpdate, true);
    }
	// 저장
	if (frame.bSave != null) {
    	scwin.cfEnableObj(frame.bSave, true);
    }
	// 삭제
	if (frame.bDelete != null) {
    	scwin.cfEnableObj(frame.bDelete, true);
    }
	// 신규
	if (frame.bCreate2 != null) {
    	scwin.cfEnableObj(frame.bCreate2, true);
    }
	// 수정
	if (frame.bUpdate2 != null) {
    	scwin.cfEnableObj(frame.bUpdate2, true);
    }
	// 저장
	if (frame.bSave2 != null) {
    	scwin.cfEnableObj(frame.bSave2, true);
    }
	// 삭제
	if (frame.bDelete2 != null) {
    	scwin.cfEnableObj(frame.bDelete2, true);
    }

};

