/**
 * @method
 * @name cfCheckExchRt
 * @description 저장버튼 클릭시 환율에 대한 체크를 하는 함수
 * @param {string} checkExchRt desc
 * @param {string} changeExchRt desc
 * @param {string} checkMain desc
 * @returns
 * @hidden N
 * @exception
 * @example   $c.gus.cfCheckExchRt(checkExchRt, changeExchRt, checkMain)
 */
scwin.cfCheckExchRt = async function (checkExchRt, changeExchRt, checkMain) {
    var checkExchRtLow 		= Math.round((checkExchRt 	* 0.9) *100)/100.00;
	var checkExchRtUpper 	= Math.round((checkExchRt 	* 1.1) *100)/100.00;

	if(checkMain == false) {
		if(changeExchRt < checkExchRtLow || changeExchRt > checkExchRtUpper) {	// 변경되는 환율이 기준 환율 값의 90% 보다 작다면
			await $c.win.alert('통화코드 선택시 환율 금액 : ' + checkExchRt 			+ '원' + '\n' +
				  '환율의 90%  가 되는 금액  : ' + checkExchRtLow 		+ '원' + '\n' +
				  '환율의 110% 가 되는 금액  : ' + checkExchRtUpper 	+ '원' + '\n' + '\n' +
				  "변경되는 환율은 기준 환율의 90% ~ 110% 값이어야  합니다.");
			return false;
		}
    }
    if(changeExchRt < checkExchRtLow || changeExchRt > checkExchRtUpper) {	// 변경되는 환율이 기준 환율 값의 90% 보다 작다면

        await $c.win.alert('통화코드 선택시 환율 금액 : ' + checkExchRt 			+ '원' + '\n' +
                '환율의 90%  가 되는 금액  : ' + checkExchRtLow 		+ '원' + '\n' +
                '환율의 110% 가 되는 금액  : ' + checkExchRtUpper 	+ '원' + '\n' + '\n' +
                "변경되는 환율은 기준 환율의 90% ~ 110% 값이어야  합니다.");
        return false;
    }
	return true;
};

/**
 * @method
 * @name cfCopyDataSetHeader
 * @description dataList 컬럼 복사
 * @param {string} oOriginDataSet desc
 * @param {string} oTargetDataSet desc
 * @returns
 * @hidden N
 * @exception
 * @example   $c.gus.cfCopyDataSetHeader
 */
scwin.cfCopyDataSetHeader = function (sourceObj, targetObj) {
    try{
		var result = null;

		if (typeof targetObj === "undefined" || targetObj == null || targetObj == ""){
			return result;
		}

		if (typeof sourceObj === "undefined" || sourceObj == null || sourceObj == ""){
			return result;
		}

		var copiedObj = null; //최종  객체
		var copiedDs = null; //최종 DS 객체

		var copyObj = null; //원본 객체
		var copyDs = null; //원본 DS 객체

		var pWin = null; //parent window
		var isParent = false;

		//parent객체를 참조해야 하는 경우
		if((typeof targetObj == "string" && targetObj.indexOf("parent") > -1) ||
		   (typeof sourceObj == "string" && sourceObj.indexOf("parent") > -1)) {

			var parentParam = $c.gus.popupParam();
		}

		//Ds객체 정보가 id값으로 넘어온 경우
		if(typeof targetObj == "string"){
			var copyParams = targetObj.split(".");

			//최종객체 찾기 
			if(copyParams.length == 1){ //자기자신인 경우
				copiedObj = $c.gus.object(copyParams[0]);
                if(typeof copiedObj === "undefined") {
                    copiedObj = $c.data.createDataList(copyParams[0]);
                }
			} else if(copyParams[0] == "parent"){ //부모창을 바라보는 경우
				isParent = true;
				copiedObj = pWin.$c.gus.object(copyParams[1]);

				for(var i=2; i<copyParams.length; i++){
					copiedObj = copiedObj.getObj(copyParams[i]);
				}
			} else if(copyParams[0] != "parent"){ //부모창을 바라보지 않는 경우(wframe)
				copiedObj = $c.gus.object(copyParams[0]);
				for(var i=1; i<copyParams.length; i++){
					copiedObj = copiedObj.getObj(copyParams[i]);
				}
			}

		} else { //DS객체로 넘어온 경우
			copiedObj = targetObj;
		}
		//객체를 찾지 못한 경우
		if(typeof copiedObj === "undefined" || copiedObj == null || copiedObj == ""){
			return -1;
		}
		//Ds객체 정보가 id값으로 넘어온 경우
		if(typeof sourceObj == "string"){
			var oriParams = sourceObj.split(".");

			//원본객체 찾기 
			if(oriParams.length == 1){ //자기자신인 경우
				copyObj = $c.gus.object(oriParams[0]);
			} else if(oriParams[0] == "parent"){ //부모창을 바라보는 경우
				copyObj = pWin.$c.gus.object(oriParams[1]);

				for(var i=2; i<oriParams.length; i++){
					copyObj = copyObj.getObj(oriParams[i]);
				}
			} else if(oriParams[0] != "parent"){
				copyObj = $c.gus.object(oriParams[0]);
				for(var i=1; i<oriParams.length; i++){
					copyObj = copyObj.getObj(oriParams[i]);
				}
			}
		} else { //DS객체로 넘어온 경우
			copyObj = sourceObj;
		}

		if(typeof copyObj === "undefined" || copyObj == null || copyObj == ""){
            $c.data.createDataList();
		}

		//ds객체 
		copiedDs = copiedObj;
		copyDs = copyObj;

		//컬럼제거
		var copiedDsColArr = copiedDs.cellIdList;
		if(copiedDsColArr.length > 0) {
			$c.gus.clear(copiedDs);
		}
        var copyDsInfo	= copyDs.getInfo();

        for(var i=0; i<copyDs.cellIdList.length; i++){
            var colId = copyDs.cellIdList[i];
            var options = {	
                "dataType":	copyDsInfo.columnInfo[colId].dataType,
                "name":		copyDsInfo.columnInfo[colId].name,
                "defaultValue":		copyDsInfo.columnInfo[colId].defaultValue,
                "length":		copyDsInfo.columnInfo[colId].length
            };

            $c.gus.insertColumn(copiedDs, 
                colId, 
                options
            );
        }
    } catch(e) {
        console.log("cfCopyDataSetHeader catch");
    }

};

/**
 * @method
 * @name cfDisable
 * @description element를 disable 시킨다.
 * @param {string} obj desc
 * @returns
 * @hidden N
 * @exception  
 * @example   $c.gus.cfDisable([])
 */
scwin.cfDisable = function (objs) {
    if(scwin.cfIsNull(objs)) {
        return;
    }

    for (var i = 0; i < objs.length; i++) {
        var obj = $c.gus.object(objs[i]);
        if(obj) {
            obj.setDisabled(true);
        }
    }
};

/**
 * @method
 * @name cfValidateMaxByteLength
 * @description 사용자의 입력값이 Byte로 환산된 최대길이를 넘을 경우 입력이 안되도록 하는 함수
 * @param {string} oElement desc
 * @param {string} length desc
 * @returns
 * @hidden N
 * @exception
 * @example   $c.gus.cfValidateMaxByteLength(this, 10)
 */
scwin.cfValidateMaxByteLength = function (oElement, length) {
	if (event.keyCode == 8 ||   // backspace
	    event.keyCode == 35 ||  // end key
	    event.keyCode == 36 ||  // home key
	    event.keyCode == 37 ||  // left key
	    event.keyCode == 38 ||  // up key
	    event.keyCode == 39 ||  // right key
	    event.keyCode == 40 ||  // down key
	    event.keyCode == 46     // delete key
	) {
	   	return true;
	}
    let obj = $c.gus.object(oElement);
    if(obj) {
        let byteLen = parseInt($c.str.getByteLength(obj.getValue()));

        if(length < byteLen) {
            return false;
        } else {
            return true;
        }
    }
};

/**
 * @method
