};

/**
 * @method
 * @name coMap
 * @description String parameter 에 대한 name과 value 쌍들을 가진 객체
 * @param
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.coMap = function () {
    this.names = new Array();
	this.values = new Array();
	this.count = 0;

	// methods
	this.getValue = function (name) {
        for (var i = 0; i < this.count; i++) {
            if (this.names[i] == name) {
                return this.values[i];
            }
        }
        return null;
    };
	this.put = function (name, value) {
        for (var i = 0; i < this.count; i++) {
            if (this.names[i] == name) {
                this.values[i] = value;
                return;
            }
        }

        this.names[this.count] = name;
        this.values[this.count++] = value;	
    };
	this.getNameAt = function(index) {
	    return this.names[index];
    };
	this.getValueAt = function(index) {
	    return this.values[index];
    };
	this.size = function() {
	    return this.count;
    };
	this.getMaxNameLength  = function() {
    	var maxLength = 0;
        for (var i = 0; i < this.count; i++) {
            if (String(this.names[i]).length > maxLength) {
                maxLength = String(this.names[i]).length;
            }
        }
    	return maxLength;
    };
};

/**
 * @method
 * @name coParameterMap
 * @description String parameter 에 대한 name과 value 쌍들을 가진 객체
 * @param
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.coParameterMap = function () {
    this.names = new Array();

	/**
	 * @type   : field
	 * @access : private
	 * @object : coParameterMap
	 * @desc   : 파라미터 값을 담고있는 array
	 */
	this.values = new Array();

	/**
	 * @type   : field
	 * @access : private
	 * @object : coParameterMap
	 * @desc   : 파라미터의 개수
	 */
	this.count = 0;

	// methods
	this.getValue = function(name) {
        for (var i = 0; i < this.count; i++) {
            if (this.names[i] == name) {
                return this.values[i];
            }
        }
	    return null;
    }
	this.put = function(name, value) {
        for (var i = 0; i < this.count; i++) {
            if (this.names[i] == name) {
                this.values[i] = value;
                return;
            }
        }
	    this.names[this.count] = name;
	    this.values[this.count++] = value;
    }
	this.getNameAt = function(index) {
    	return this.names[index];
    }
	this.getValueAt = function(index) {
	    return this.values[index];
    };
	this.size = function() {
	    return this.count;
    };
	this.getMaxNameLength  = function() {
        var maxLength = 0;
        for (var i = 0; i < this.count; i++) {
            if (String(this.names[i]).length > maxLength) {
                maxLength = String(this.names[i]).length;
            }
        }
	    return maxLength;
    };
	this.getMaxValueLength = function() {
    	var maxLength = 0;
    	for (var i = 0; i < this.count; i++) {
            if (String(this.values[i]).length > maxLength) {
                maxLength = String(this.values[i]).length;
            }
    	}
	    return maxLength;
    };
};

/**
 * @method
 * @name cfInitHidVal
 * @description 초기화시킨다.  ID를 넘기면 그 안에 포함된 모든 오브젝트를 초기화
 * @param {string} obj desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.cfInitHidVal = function (obj) {
    let sObj = $c.gus.object(obj);
    if(sObj) {
        try {
            var obj1=null;
            if(typeof obj === "object" && obj.getPluginName() !== "group") {
                for (var i = 0; i < sObj.length; i++) {
                    obj1 = $c.gus.object(sObj[i]);
                    if(obj1) {
                        obj1.setValue("");
                    }
                }
            } else {
                let objArr = $c.util.getChildren(sObj, {
                    excludePlugin: "body calendar group textbox output image span trigger anchor",
                    recursive: true
                });
                for (let i = 0; i < objArr.length; i++) {
                    obj1 = $c.gus.object(objArr[i]);
                    obj1.setValue("");
                }
            }
        } catch(e) {
            console.log("catch cfInitHidVal");
        }
    } else {
        return;
    }

};

/**
 * @method
 * @name cfInitObjects
 * @description 오브젝트의 값을 초기화시킨다
 * @param {object} array 이거나 group 이거나
 * @param {object} excpt 제외 컴포넌트
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.cfInitObjects = function (obj, excpt) {
	let sObj = $c.gus.object(obj);
    if(sObj) {
        try {
            let obj1 = null;
            if(Object.prototype.toString.call(obj) === "[object Array]") {
                for (let i = 0; i < sObj.length; i++) {
                    obj1 = $c.gus.object(sObj[i]);
                    if(obj1) {
                        obj1.setValue("");
                    }
                }
            } else {
                let objArr = $c.util.getChildren(sObj, {
                    excludePlugin: "body calendar group textbox output image span trigger anchor",
                    recursive: true
                });

                let excptId = [];
                if(!$c.gus.cfIsNull(excpt)) {
                    excpt.forEach(function(id) {
                        // excptId.push(id.org_id);
                        excptId.push(id);
                    });
                }

                for (let i = 0; i < objArr.length; i++) {
                    obj1 = $c.gus.object(objArr[i]);
                    // if(!excptId.includes(obj1.org_id)) {
                    if(!excptId.includes(obj1)) {
                        switch(obj1.getPluginName()) { // udc 일때 error 처리
                            case 'selectbox' :
                            case 'autoComplete' :
                                obj1.setSelectedIndex(0);
                                break;
                            case 'checkbox' :
                                obj1.checkAll(false);
                                break;
                            case 'input' :
                            case 'inputCalendar' :
                            case 'textarea' :
                            case 'radio' :
                                obj1.setValue("");
                                break;
                            default :
                                break;
                        }
                    }
                }
            }
        } catch(e) {
            console.log("catch cfInitHidVal");
        }
    } else {
        return;
    }
};

