};

/**
 * @method
 * @name cfDownloadFile
 * @description 해당 파일을 다운로드 한다.
 * @param {string} fileName desc
 * @param {string} filePath desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.cfDownloadFile = async function (fileName, filePath) {
	var FILE_URL = await scwin.cfGetTargetFileURL(fileName,filePath,"DOWN");
    WebSquare.net.download(FILE_URL);
};

scwin.buildDownloadRequestURL = function (fileName, filePath, fileType) {
    if ($c.util.isEmpty(filePath)) {
        return "";
    }

    return "/s3upload.do?" + new URLSearchParams({
        path: filePath,
        fileName: fileName || "",
        fileType: fileType || "DOWN",
        fallback: "true",
        PGM_ID: $c.global.PGM_ID || "",
        CALLER_URL: $c.global.CALLER_URL || ""
    }).toString();
};

scwin.cfDownloadFile = async function (fileName, filePath) {
    if ($c.util.isEmpty(filePath)) {
        $c.win.alert("대상 파일이 NULL입니다. 설정값을 확인하세요.");
        return;
    }

    try {
        const response = await fetch(scwin.buildDownloadRequestURL(fileName, filePath, "DOWN"));

        if (response.status === 404) {
            $c.win.alert("해당 파일[" + filePath + "]이 존재하지 않습니다.");
            return;
        }

        if (!response.ok) {
            $c.win.alert("파일 다운로드 중 오류가 발생했습니다.");
            return;
        }

        const result = await response.json();
        if (!result.downloadUrl) {
            $c.win.alert("다운로드 URL 생성에 실패했습니다.");
            return;
        }

        window.location.href = result.downloadUrl;
    } catch (e) {
        console.error(e);
        $c.win.alert("다운로드 처리 중 예외가 발생했습니다.");
    }
};

/**
 * @method
 * @name cfAlertMsg
 * @description 공통메세지에 정의된 메세지를 alert box로 보여준 후 리턴한다
 * @param {string} msgId desc
 * @param {string} paramArray desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.cfAlertMsg = async function (msgId, paramArray) {
   	if (scwin.cfIsNull(msgId)) {
		await $c.win.alert("존재하지 않는 메시지입니다.");
		return null;
	}
    let tmpMessage = msgId;
    if(typeof paramArray !== "undefined" && paramArray.length > 0) {
        for (let i = 0; i < paramArray.length; i++) {
            if ($c.util.isEmpty(paramArray[i]) === false) {
                tmpMessage = (tmpMessage.indexOf("%") != -1) ? $c.str.replaceAll(tmpMessage, "%"+(i+1), paramArray[i]) : tmpMessage;
            }
        }
    }
	await $c.win.alert(tmpMessage);
	return tmpMessage;
};

